package unverified;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair3141DifferenceFindingTest {

    private final ClonePair3141 subject = new ClonePair3141();

    /**
     * Generated by Codex (GPT-5.5).
     */
    @Test
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{new float[]{0.0f, -0.0f}};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((float[]) values[0]), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((float[]) values[0]), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Float(-0.0)",
            null,
            "java.lang.Object[][float[][0.0, -0.0]]",
            "java.lang.Object[][float[][0.0, -0.0]]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Float(0.0)",
            null,
            "java.lang.Object[][float[][0.0, -0.0]]",
            "java.lang.Object[][float[][0.0, -0.0]]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
